const item = $input.item.json;
const accountId = item.account_id;

// Parse LLM response
let raw = item.choices[0].message.content.trim();
raw = raw.replace(/^```json\s*/m, '').replace(/\s*```$/m, '').trim();

let memo;
try {
  memo = JSON.parse(raw);
} catch (e) {
  throw new Error(`JSON parse failed for ${accountId}: ${e.message}`);
}
memo.account_id = accountId;

// Ensure required list fields exist
['services_supported','emergency_definition','integration_constraints',
 'questions_or_unknowns','special_routing_rules'].forEach(f => {
  if (!Array.isArray(memo[f])) memo[f] = memo[f] ? [memo[f]] : [];
});

return [{ json: { account_id: accountId, file_name: item.file_name, memo } }];

const { account_id, file_name, memo } = $input.item.json;

// ── Build system prompt ──────────────────────────────────
const company = memo.company_name || 'the company';
const bh = memo.business_hours || {};
const days = bh.days || 'Monday through Friday';
const start = bh.start || '8:00 AM';
const end = bh.end || '5:00 PM';
const tz = bh.timezone || 'local time';
const exc = bh.exceptions || null;

const tzMap = {
  'America/Chicago':'CT','America/New_York':'ET','America/Denver':'MT',
  'America/Los_Angeles':'PT','America/Phoenix':'MST'
};
const tzAbbr = tzMap[tz] || tz;

const hrs = `${days} from ${start} to ${end} ${tzAbbr}` + (exc ? `, with ${exc}` : '');

const er = memo.emergency_routing_rules || {};
const tr = memo.call_transfer_rules || {};
const ne = memo.non_emergency_routing_rules || {};
const services = (memo.services_supported || []).join(', ') || 'a range of services';
const emrgDef = (memo.emergency_definition || []).join('; ') || 'urgent safety situations';
const pricing = memo.pricing_instructions || 'do not quote specific prices; a team member will provide an exact quote';
const tone = memo.tone_instructions || 'professional, friendly, and helpful';

const specialRules = (memo.special_routing_rules || []).map(r =>
  `- If caller mentions ${r.trigger}: ${r.action}${r.contact_name ? ` (Contact: ${r.contact_name}${r.contact_phone ? ' at ' + r.contact_phone : ''})` : ''}`
).join('\n');

const systemPrompt = `# ${company} AI Receptionist — System Prompt

## IDENTITY
You are a professional, friendly receptionist for ${company}. You answer calls on their behalf, help callers with their needs, and connect them with the right team.

## TONE
${tone}

## BUSINESS INFORMATION
- Company: ${company}
- Address: ${memo.office_address || 'our office'}
- Services: ${services}
- Business Hours: ${hrs}

## PRICING POLICY
${pricing}

---

## DURING BUSINESS HOURS — CALL FLOW

**Step 1 — Greeting**
"Thank you for calling ${company}, how can I help you today?"

**Step 2 — Collect information (only what is needed)**
- Caller full name
- Callback phone number
- Service address
- Brief description of issue or request

**Step 3 — Transfer**
Say: "Let me connect you with ${tr.transfer_contact_name || 'our team'} right now."
Initiate transfer to ${tr.transfer_number || '[DISPATCH NUMBER]'}.

**Step 4 — If Transfer Fails**
Say: "${tr.message_if_transfer_fails || 'I was unable to connect you directly, but someone will call you back shortly'}. Someone will reach you within ${tr.callback_window_if_fails || 'as soon as possible'}."
Confirm name and number before closing.

**Step 5 — Confirm next steps, ask "anything else", close warmly.**

---

## AFTER HOURS — CALL FLOW

**Step 1 — Greeting**
"Thank you for calling ${company}. Our office is currently closed. I'm here to help — what's going on?"

**Step 2 — Determine if emergency**
Emergencies include: ${emrgDef}
Ask: "Is this something that needs immediate attention tonight, or can it wait until we open?"

**Step 3a — IF EMERGENCY:**
Collect: full name, callback number, service address, brief description.
Say: "Let me connect you with our on-call team right now."
Transfer to ${er.primary_contact_name || 'on-call'} at ${er.primary_contact_phone || '[EMERGENCY NUMBER]'}.
${er.secondary_contact_phone ? `If no answer, try ${er.secondary_contact_name || 'backup'} at ${er.secondary_contact_phone}.` : ''}
If no answer after ${er.rings_before_fallback || 3} rings: "${er.fallback_instruction || 'Our on-call team has been alerted and will call you back as quickly as possible.'}"

**Step 3b — IF NOT EMERGENCY:**
${ne.action || 'Take a message'}.
Confirm: "Our team will be in touch ${ne.callback_window || 'during business hours'}."

**Step 4 — Ask "anything else", close warmly.**

---
${specialRules ? '## SPECIAL ROUTING RULES\n' + specialRules + '\n---' : ''}

## RULES
1. Never mention function calls, tools, or system actions to callers.
2. Never quote specific prices or commit to appointment times.
3. Only collect: name, phone, address, issue. Do not ask unnecessary questions.
4. If unsure about a specific question, say our team will address it on callback.
5. Always confirm collected info before ending the call.
6. Always end with: "Is there anything else I can help you with?"
`;

// ── Build full agent spec ───────────────────────────────
const agentSpec = {
  agent_name: `${company} - Clara AI Agent`,
  account_id,
  version: 'v1',
  voice_style: {
    provider: 'elevenlabs',
    voice_id: 'rachel',
    style: 'friendly and professional',
    speed: 1.0,
    custom_note: tone
  },
  system_prompt: systemPrompt,
  key_variables: {
    company_name: company,
    timezone: tz,
    timezone_abbr: tzAbbr,
    business_hours_days: days,
    business_hours_start: start,
    business_hours_end: end,
    business_hours_exceptions: exc,
    office_address: memo.office_address,
    primary_emergency_contact_name: er.primary_contact_name,
    primary_emergency_contact_phone: er.primary_contact_phone,
    secondary_emergency_contact_name: er.secondary_contact_name,
    secondary_emergency_contact_phone: er.secondary_contact_phone,
    transfer_number: tr.transfer_number,
    transfer_contact_name: tr.transfer_contact_name
  },
  tool_invocation_placeholders: {
    note: 'Do NOT mention tool calls, function names, or system actions to callers.',
    transfer_call: {
      trigger: 'caller needs to reach dispatch or team member',
      action: 'transfer_call',
      number: tr.transfer_number,
      caller_message: `One moment while I connect you with ${tr.transfer_contact_name || 'our team'}.`
    },
    send_sms: {
      trigger: 'caller needs a callback or agent takes a message',
      action: 'send_sms_to_team',
      note: 'Send message to team without disclosing this to caller'
    }
  },
  call_transfer_protocol: {
    primary_transfer_number: tr.transfer_number,
    contact_name: tr.transfer_contact_name,
    timeout_rings: tr.timeout_rings || 4,
    on_transfer_fail: tr.message_if_transfer_fails,
    callback_window_if_fails: tr.callback_window_if_fails,
    what_to_collect_before_transfer: ['caller full name','callback phone number','service address','brief description of issue']
  },
  fallback_protocol: {
    trigger: 'transfer fails after timeout_rings',
    action: [
      'Apologize for the inconvenience',
      `Say: '${tr.message_if_transfer_fails || "I was unable to connect you but someone will call you back shortly"}'`,
      'Confirm their name and number',
      `Assure callback within ${tr.callback_window_if_fails || 'as soon as possible'}`,
      'Ask if there is anything else before closing'
    ]
  },
  emergency_protocol: {
    definition: memo.emergency_definition || [],
    primary_transfer: { name: er.primary_contact_name, phone: er.primary_contact_phone, rings_before_fallback: er.rings_before_fallback || 3 },
    secondary_transfer: er.secondary_contact_phone ? { name: er.secondary_contact_name, phone: er.secondary_contact_phone } : null,
    if_no_answer: er.fallback_instruction
  },
  conversation_hygiene: {
    max_info_to_collect: ['name','callback number','address','issue description'],
    never_say: ['function call','tool','transfer function','system','I am an AI','I am a bot'],
    pricing_policy: pricing,
    always_end_with: 'Is there anything else I can help you with before I let you go?'
  }
};

return [{ json: { account_id, memo, agent_spec: agentSpec } }];

