  throw new Error(`JSON parse failed for ${accountId} v2: ${e.message}`);
}
v2Memo.account_id = accountId;

['services_supported','emergency_definition','integration_constraints',
 'questions_or_unknowns','special_routing_rules'].forEach(f => {
  if (!Array.isArray(v2Memo[f])) v2Memo[f] = v2Memo[f] ? [v2Memo[f]] : [];
});

// ── Compute changelog ──────────────────────────────────
function diffValues(v1, v2, path, changes) {
  if (typeof v1 === 'object' && v1 !== null && typeof v2 === 'object' && v2 !== null &&
      !Array.isArray(v1) && !Array.isArray(v2)) {
    const keys = new Set([...Object.keys(v1), ...Object.keys(v2)]);
    keys.forEach(k => diffValues(v1[k], v2[k], path ? `${path}.${k}` : k, changes));
  } else if (Array.isArray(v1) && Array.isArray(v2)) {
    const v1s = v1.filter(x => typeof x !== 'object');
    const v2s = v2.filter(x => typeof x !== 'object');
    const added = v2s.filter(x => !v1s.includes(x));
    const removed = v1s.filter(x => !v2s.includes(x));
    if (added.length) changes.push({ field: path, change_type: 'items_added', added, reason: 'Updated during onboarding' });
    if (removed.length) changes.push({ field: path, change_type: 'items_removed', removed, reason: 'Updated during onboarding' });
  } else if (v1 !== v2) {
    const type = v1 === null || v1 === undefined ? 'field_added' : v2 === null || v2 === undefined ? 'field_cleared' : 'value_updated';
    changes.push({ field: path, change_type: type, old_value: v1, new_value: v2, reason: 'Updated during onboarding call' });
  }
}

const changes = [];
diffValues(v1Memo, v2Memo, '', changes);

const changesJson = {
  account_id: accountId,
  company_name: v2Memo.company_name,
  version_from: 'v1',
  version_to: 'v2',
  generated_at: new Date().toISOString(),
  total_changes: changes.length,
  changes
};

// ── Build markdown changelog ───────────────────────────
let md = `# Changelog — ${v2Memo.company_name || accountId}\n`;
md += `**Account ID:** \`${accountId}\`  \n`;
md += `**Version:** v1 → v2  \n`;
md += `**Generated:** ${changesJson.generated_at}  \n`;
md += `**Total Changes:** ${changes.length}\n\n---\n\n## Changes\n\n`;

if (changes.length === 0) {
  md += '_No changes detected._\n';
} else {
  changes.forEach(c => {
    md += `### \`${c.field}\`\n`;
    md += `- **Type:** ${c.change_type}\n`;
    if (c.old_value !== undefined) md += `- **Old:** \`${JSON.stringify(c.old_value)}\`\n`;
    if (c.new_value !== undefined) md += `- **New:** \`${JSON.stringify(c.new_value)}\`\n`;
    if (c.added) md += `- **Added:** ${JSON.stringify(c.added)}\n`;
    if (c.removed) md += `- **Removed:** ${JSON.stringify(c.removed)}\n`;
    md += `- **Reason:** ${c.reason}\n\n`;
  });
}

return [{ json: { account_id: accountId, v1_memo: v1Memo, v2_memo: v2Memo, changes_json: changesJson, changes_md: md } }];

